## components/Portfolio.tsx

```typescript
import React, { useState, useEffect } from 'react';
import { X, ExternalLink, Instagram, Play, Heart, Volume2, VolumeX, Plus, Grid, Camera, Clapperboard, Palette, Layers, ArrowLeft } from 'lucide-react';
import { ASSETS } from '../data/assets'; // IMPORT ASSETS

/**
 * PORTFOLIO COMPONENT
 * Displays Works (Images) and Reels (Videos).
 * Data is pulled from src/data/assets.ts for easy updating.
 */

// Categorías definidas con Iconos y Claves de mapeo
const filterCategories = [
  { id: 'all', label: 'Todo', icon: <Grid size={16} /> },
  { id: 'video', label: 'Video / Reels', icon: <Clapperboard size={16} /> },
  { id: 'photo', label: 'Fotografía', icon: <Camera size={16} /> },
  { id: 'branding', label: 'Branding', icon: <Palette size={16} /> }
];

const Portfolio: React.FC = () => {
  const [activeFilter, setActiveFilter] = useState("all");
  // State for the Image Lightbox
  const [selectedWork, setSelectedWork] = useState<typeof ASSETS.portfolio.works[0] | null>(null);
  // State for the Video Player Modal
  const [selectedReel, setSelectedReel] = useState<typeof ASSETS.portfolio.reels[0] | null>(null);
  const [isMuted, setIsMuted] = useState(true);

  // Pagination State
  const [visibleItems, setVisibleItems] = useState(6);
  const [filteredWorks, setFilteredWorks] = useState(ASSETS.portfolio.works);

  // 1. Filter Logic: Updates when activeFilter changes
  useEffect(() => {
    const works = ASSETS.portfolio.works;

    // Mapeo del ID del filtro al string de categoría en los datos
    let categoryString = "";
    if (activeFilter === 'photo') categoryString = "Fotografía";
    if (activeFilter === 'branding') categoryString = "Branding";
    // Nota: 'video' no filtra 'works' porque los videos están en 'reels', 
    // a menos que agregues items con categoría "Video" en works.

    if (activeFilter === 'all') {
      setFilteredWorks(works);
    } else if (activeFilter === 'video') {
       // Si hay trabajos mixtos de video en la grilla principal, se mostrarían aquí.
       // Por ahora filtramos si existiera la categoría, si no, quedará vacío y se verán solo los Reels.
       setFilteredWorks(works.filter(work => work.category === "Video"));
    } else {
       setFilteredWorks(works.filter(work => work.category === categoryString));
    }

    setVisibleItems(6); // Reset pagination on filter change
  }, [activeFilter]);

  const handleLoadMore = () => {
    setVisibleItems(prev => prev + 3);
  };

  // Logic to determine if sections should be visible
  const showWorksGrid = filteredWorks.length > 0;
  const showReelsSection = activeFilter === 'all' || activeFilter === 'video';

  return (
    <section id="portfolio" className="py-32 bg-movie-black relative min-h-screen">
      {/* Background Decor */}
      <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-movie-red/5 blur-[120px] rounded-full pointer-events-none"></div>

      <div className="container mx-auto px-6 relative z-10">

        {/* Header */}
        <div className="text-center mb-12">
           <h2 className="text-movie-red font-bold tracking-[0.3em] text-sm uppercase mb-4">Nuestro Trabajo</h2>
           <h3 className="text-5xl md:text-6xl font-heading font-black text-white mb-8">PORTAFOLIO</h3>

           {/* MODERN FILTER CONTROLS */}
           <div className="flex flex-wrap justify-center gap-4 bg-white/5 p-2 rounded-full border border-white/10 w-fit mx-auto backdrop-blur-sm">
             {filterCategories.map(cat => (
               <button
                 key={cat.id}
                 onClick={() => setActiveFilter(cat.id)}
                 className={`flex items-center gap-2 px-6 py-3 text-xs font-bold uppercase tracking-wider rounded-full transition-all duration-300 ${
                   activeFilter === cat.id 
                     ? 'bg-movie-red text-white shadow-[0_0_20px_rgba(176,35,46,0.4)] transform scale-105' 
                     : 'bg-transparent text-movie-silver hover:bg-white/10 hover:text-white'
                 }`}
               >
                 {cat.icon} {cat.label}
               </button>
             ))}
           </div>
        </div>

        {/* 2. Works Gallery (Images) - Only visible if there are items */}
        {showWorksGrid && (
          <div className="animate-fade-in-up">
             {activeFilter !== 'video' && (
                <div className="flex items-center gap-4 mb-8">
                   <h4 className="text-2xl font-heading font-bold text-white uppercase italic">Galería & Proyectos</h4>
                   <div className="h-px bg-white/10 flex-1"></div>
                </div>
             )}

            <div className="columns-1 md:columns-2 lg:columns-3 gap-8 space-y-8 mb-12">
              {filteredWorks.slice(0, visibleItems).map((work) => (
                <div 
                  key={work.id} 
                  onClick={() => setSelectedWork(work)}
                  className="group relative overflow-hidden rounded-lg break-inside-avoid cursor-pointer bg-movie-dark border border-white/5 hover:border-movie-red/50 transition-all hover:shadow-2xl hover:-translate-y-1"
                >
                  <div className="relative aspect-[3/4] md:aspect-auto overflow-hidden">
                     {/* Overlay Gradient on Hover */}
                     <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-0 group-hover:opacity-80 transition-opacity duration-300 z-10"></div>

                     <img 
                      src={work.img} 
                      alt={`Portafolio ${work.category} - ${work.title} - La Movie Agency`}
                      className="w-full h-auto object-cover transition-all duration-700 group-hover:scale-110"
                      loading="lazy"
                    />

                    {/* Floating Category Tag */}
                    <div className="absolute top-4 left-4 z-20 opacity-0 group-hover:opacity-100 transition-opacity duration-300 transform -translate-y-2 group-hover:translate-y-0">
                       <span className="bg-movie-red text-white text-[10px] font-bold px-3 py-1 rounded-full uppercase tracking-widest shadow-lg">
                          {work.category}
                       </span>
                    </div>

                    <div className="absolute bottom-0 left-0 w-full p-6 z-20 translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-500">
                      <h4 className="text-white text-xl font-heading font-bold mb-1">{work.title}</h4>
                      <p className="text-white/70 text-xs uppercase tracking-wider">{work.client}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {/* Load More Button */}
            {visibleItems < filteredWorks.length && (
              <div className="text-center mb-24">
                 <button 
                   onClick={handleLoadMore}
                   className="inline-flex items-center gap-2 px-8 py-3 border border-white/20 text-white hover:bg-white hover:text-black hover:border-white transition-all duration-300 font-bold uppercase tracking-widest rounded-full group"
                 >
                   <Plus size={16} className="group-hover:rotate-90 transition-transform duration-300" /> Cargar Más
                 </button>
              </div>
            )}
          </div>
        )}

        {/* No results message */}
        {!showWorksGrid && !showReelsSection && (
            <div className="text-center py-20 animate-fade-in">
                <p className="text-movie-silver text-lg">No hay proyectos en esta categoría por el momento.</p>
            </div>
        )}


        {/* 3. Reels Section (Vertical Video) - Conditionally rendered */}
        {showReelsSection && (
          <div className="mb-16 border-t border-white/10 pt-16 animate-fade-in-up">
             <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-12">
                <div className="flex items-center gap-4">
                   <div className="w-14 h-14 bg-gradient-to-tr from-yellow-400 via-red-500 to-purple-500 rounded-full p-[2px] animate-spin-slow">
                      <div className="w-full h-full bg-movie-black rounded-full flex items-center justify-center border border-white/10">
                        <Instagram size={28} className="text-white" />
                      </div>
                   </div>
                   <div>
                      <h3 className="text-3xl font-heading font-bold text-white uppercase italic">Reels & TikToks</h3>
                      <p className="text-movie-silver text-sm">Formato vertical de alto rendimiento.</p>
                   </div>
                </div>

                <a href="https://www.instagram.com/ads_yosii/" target="_blank" rel="noreferrer" className="group inline-flex items-center gap-2 px-6 py-3 bg-white/5 hover:bg-white hover:text-black text-white text-xs font-bold uppercase tracking-widest rounded-full transition-all duration-300">
                  Ver Feed Completo <ExternalLink size={14} />
                </a>
             </div>

             <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                {ASSETS.portfolio.reels.map((reel) => (
                  <div 
                    key={reel.id} 
                    onClick={() => setSelectedReel(reel)}
                    className="relative aspect-[9/16] group cursor-pointer overflow-hidden rounded-xl border border-white/10 bg-movie-dark hover:shadow-[0_0_30px_rgba(176,35,46,0.3)] transition-all duration-500 transform hover:-translate-y-2 hover:border-movie-red/50"
                  >
                     <img 
                       src={reel.img} 
                       alt={`Video Reel ${reel.title} - Producción Audiovisual`}
                       className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-all duration-500 group-hover:scale-110" 
                       loading="lazy"
                     />

                     <div className="absolute inset-0 bg-gradient-to-b from-transparent via-transparent to-black opacity-90"></div>

                     <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-16 h-16 bg-white/10 backdrop-blur-md rounded-full flex items-center justify-center scale-75 group-hover:scale-100 transition-transform duration-300 ease-out border border-white/30 group-hover:bg-movie-red/80 group-hover:border-movie-red">
                        <Play size={24} className="text-white fill-white ml-1" />
                     </div>

                     <div className="absolute bottom-0 left-0 w-full p-4 translate-y-2 group-hover:translate-y-0 transition-transform duration-300">
                        <h5 className="text-white font-bold text-sm truncate mb-2">{reel.title}</h5>
                        <div className="flex items-center justify-between text-xs text-white/80">
                           <div className="flex items-center gap-1 bg-black/50 px-2 py-1 rounded-full backdrop-blur"><Play size={10} className="fill-white" /> {reel.views}</div>
                           <div className="flex items-center gap-1 bg-black/50 px-2 py-1 rounded-full backdrop-blur"><Heart size={10} className="fill-white" /> {reel.likes}</div>
                        </div>
                     </div>

                     <div className="absolute top-3 right-3 p-1.5 bg-black/50 backdrop-blur-sm rounded-full border border-white/10">
                        <Instagram size={12} className="text-white" />
                     </div>
                  </div>
                ))}
             </div>
          </div>
        )}

      </div>

      {/* 4. MODALS (Popups) */}

      {/* Lightbox Modal (For Images) */}
      {selectedWork && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/95 backdrop-blur-md p-4 animate-fade-in">
          <button onClick={() => setSelectedWork(null)} className="absolute top-6 right-6 text-white/50 hover:text-movie-red transition-colors z-50 p-2 bg-black/50 rounded-full">
            <X size={32} />
          </button>

