// Main App Component
const App: React.FC = () => {
  const [lang, setLang] = useState<'es' | 'en'>('es');
  const [loading, setLoading] = useState(true);

  const toggleLanguage = () => {
    setLang(prev => prev === 'es' ? 'en' : 'es');
  };

  useEffect(() => {
    // Fake loading delay for preloader
    const timer = setTimeout(() => setLoading(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  return (
    <HashRouter>
        <Preloader isLoading={loading} />
        <ScrollToTop />
        <Layout lang={lang} toggleLanguage={toggleLanguage}>
            <Routes>
                <Route path="/" element={<Home lang={lang} t={translations[lang]} />} />
                <Route path="/services" element={<ServicesPage />} />
                <Route path="/events" element={<EventCoverage />} />
                <Route path="/portfolio" element={<Portfolio />} />
                <Route path="/resources" element={<div className="animate-reveal"><Templates /><PrintStudio /><PackCreator /></div>} />
                <Route path="/ai" element={<div className="animate-reveal"><AIAgents onBack={() => window.history.back()} onOpenForm={() => window.open('https://wa.me/573017355046', '_blank')} /></div>} />
                <Route path="/contact" element={<div className="animate-reveal pt-20"><Contact /><FAQ /></div>} />
                <Route path="/policies" element={<Policies onBack={() => window.history.back()} />} />
            </Routes>
        </Layout>

        {/* Global Modals or Overlays can go here */}

    </HashRouter>
  );
};

export default App;
